import { Feature } from 'geojson';
import { type ReactNode, Children } from 'react';

import { _accessValue as accessValue } from '@dynatrace/strato-components/core';

import { isComponent } from './is-component.js';
import { BubbleLayer } from '../components/BubbleLayer/BubbleLayer.js';
import { ChoroplethLayer } from '../components/ChoroplethLayer/ChoroplethLayer.js';
import { ConnectionLayer } from '../components/ConnectionLayer/ConnectionLayer.js';
import { DotLayer } from '../components/DotLayer/DotLayer.js';
import {
  MAX_LATITUDE,
  MAX_LONGITUDE,
  MIN_LATITUDE,
  MIN_LONGITUDE,
} from '../constants.js';
import { InternalChoroplethLayerProps } from '../types/choropleth-layer.js';
import type { Location } from '../types/location.js';
import type { BoundingBoxCoords } from '../types/map-view.js';

const narrowDownLocationBounds = (
  coordinates: Location[],
  initialBounds: BoundingBoxCoords,
) => {
  const bounds: BoundingBoxCoords = [...initialBounds];
  coordinates.forEach(({ latitude, longitude }) => {
    bounds[0] = Math.min(bounds[0], longitude);
    bounds[1] = Math.min(bounds[1], latitude);
    bounds[2] = Math.max(bounds[2], longitude);
    bounds[3] = Math.max(bounds[3], latitude);
  });

  return bounds;
};

const updateChoroplethBounds = (
  locationBounds: BoundingBoxCoords,
  initialBounds: BoundingBoxCoords,
) => {
  const bounds: BoundingBoxCoords = [...initialBounds];
  bounds[0] = Math.min(bounds[0], locationBounds[0]);
  bounds[1] = Math.min(bounds[1], locationBounds[1]);
  bounds[2] = Math.max(bounds[2], locationBounds[2]);
  bounds[3] = Math.max(bounds[3], locationBounds[3]);

  return bounds;
};

const narrowDownChoroplethBounds = (
  props: InternalChoroplethLayerProps<Record<string, unknown>>,
  featureCollection: Feature[],
  bounds: BoundingBoxCoords,
) => {
  const locations = props.data.map((feat) => {
    const accessor = props.regionAccessor;
    if (typeof accessor === 'string') {
      return accessValue<string>(feat, accessor);
    } else {
      return accessor(feat);
    }
  });

  let foundLocations = 0;
  for (const feature of featureCollection) {
    if (locations.includes(feature.id as string)) {
      if (feature.properties?.bbox) {
        bounds = updateChoroplethBounds(feature.properties.bbox, bounds);
        foundLocations++;
      }
    }
    if (foundLocations === locations.length) {
      break;
    }
  }

  return bounds;
};

export const getDataLayersBoundingBox = (
  children: ReactNode,
  featureCollection?: Feature[],
): BoundingBoxCoords => {
  let bounds: BoundingBoxCoords = [
    MAX_LONGITUDE,
    MAX_LATITUDE,
    MIN_LONGITUDE,
    MIN_LATITUDE,
  ];

  Children.forEach(children, (child) => {
    if (isComponent(child, BubbleLayer) || isComponent(child, DotLayer)) {
      const data = child.props.data;

      bounds = narrowDownLocationBounds(data, bounds);
    } else if (isComponent(child, ConnectionLayer)) {
      const connectionsProps = child.props;
      connectionsProps.data.forEach(({ path }) => {
        bounds = narrowDownLocationBounds(path, bounds);
      });
    } else if (isComponent(child, ChoroplethLayer)) {
      if (featureCollection !== undefined) {
        bounds = narrowDownChoroplethBounds(
          child.props,
          featureCollection,
          bounds,
        );
      }
    }
  });

  return bounds;
};
